const r=".btn{display:inline-flex;align-items:center;justify-content:center;border-radius:10px;padding:.56rem .92rem;border:1px solid transparent;font-size:.87rem;font-weight:700;line-height:1;cursor:pointer;transition:transform .14s ease,background-color .16s ease,color .16s ease,border-color .16s ease}.btn:disabled{opacity:.6;cursor:not-allowed;transform:none}.btn:hover:not(:disabled){transform:translateY(-1px)}.btn-primary{color:#fff;background:linear-gradient(120deg,var(--accent-1),var(--accent-2) 50%,var(--accent-3));box-shadow:0 10px 20px -14px #ff2f6dd9}.btn-primary:hover:not(:disabled){filter:brightness(1.05)}.btn-outline{background:#ffffff08;color:var(--text-2);border-color:var(--border)}.btn-outline:hover:not(:disabled){color:var(--text-1);background:#ffffff14}";export{r as s};
